import{_ as a,o as t,c as o,a3 as i}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Castle","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/castle.md","filePath":"cosmos/framework/packages/castle.md","lastUpdated":1783216089000}'),s={name:"cosmos/framework/packages/castle.md"};function d(r,e,n,l,c,h){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="xihan-framework-castle" tabindex="-1">XiHan.Framework.Castle <a class="header-anchor" href="#xihan-framework-castle" aria-label="Permalink to &quot;XiHan.Framework.Castle&quot;">​</a></h1><blockquote><p>AOP 动态代理：Castle DynamicProxy 集成，把框架异步拦截器织入服务方法。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Castle</code></li><li><strong>模块类</strong>：<code>XiHanCastleModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Castle 是框架的 AOP（面向切面）底座。它集成 Castle DynamicProxy，在服务注册完成后，自动为注册了拦截器的接口服务生成动态代理，并把框架自己的异步拦截器链（<code>IXiHanInterceptor</code>）适配到 Castle 的同步 <code>IInterceptor</code> 模型上。工作单元（Uow）、缓存（Caching）等模块的方法级切面能力正是建立在它之上。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要给服务方法透明地织入横切逻辑（事务、缓存、审计等），而不侵入业务代码。</li><li>你的模块要注册自定义拦截器，让被 <code>[DependsOn]</code> 的接口服务自动被代理。</li><li>依赖 Uow / Caching 等基于拦截器的能力时，需要引入这个 AOP 前置包。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Castle</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanCastleModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>PostConfigureServices</code> 阶段调用 <code>AddCastleDynamicProxy()</code>：遍历 DI 容器，为满足条件（接口 + 有实现类 + 未被忽略 + 至少注册了一个拦截器）的服务，用代理版本替换原注册。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>Castle DynamicProxy 集成</strong>：基于 <code>Castle.Core</code> 生成接口代理。</li><li><strong>异步拦截器链适配</strong>：<code>CastleInterceptorAdapter</code> 把框架的 <code>IXiHanInterceptor[]</code> 链适配为 Castle 同步 <code>IInterceptor</code>，支持 <code>void</code> / <code>Task</code> / <code>Task&lt;T&gt;</code> 返回值。</li><li><strong>方法调用上下文包装</strong>：<code>CastleXiHanMethodInvocation</code> 把 Castle 的 <code>IInvocation</code> 适配为框架的 <code>IXiHanMethodInvocation</code>（参数、返回值、泛型参数、目标对象等）。</li><li><strong>DI 自动代理化</strong>：<code>AddCastleDynamicProxy()</code> 在注册阶段自动识别需代理的服务，无需手工逐个配置。</li><li><strong>拦截器注册回调</strong>：各模块通过 <code>OnRegistered</code> 回调把拦截器加入拦截链，按注册顺序执行。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>XiHanCastleModule</code></td><td>模块类，<code>PostConfigureServices</code> 阶段启动代理化</td></tr><tr><td><code>CastleInterceptorAdapter</code></td><td>实现 Castle <code>IInterceptor</code>，适配框架的 <code>IXiHanInterceptor[]</code> 链</td></tr><tr><td><code>CastleXiHanMethodInvocation</code></td><td>实现 <code>IXiHanMethodInvocation</code>，适配 Castle 的 <code>IInvocation</code></td></tr><tr><td><code>ServiceCollectionCastleExtensions</code></td><td>DI 扩展，含 <code>AddCastleDynamicProxy()</code></td></tr></tbody></table><blockquote><p>拦截器抽象本身（<code>IXiHanInterceptor</code>、<code>IXiHanMethodInvocation</code>、<code>XiHanInterceptor</code>）定义在 <a href="./core">XiHan.Framework.Core</a>，本包只提供 Castle 实现。</p></blockquote><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>内部依赖：仅 <a href="./core">XiHan.Framework.Core</a>（提供拦截器抽象与 <code>DynamicProxy</code> 契约）。</li><li>第三方核心：<code>Castle.Core</code>（Castle DynamicProxy）。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./uow">XiHan.Framework.Uow</a> — <code>UnitOfWorkInterceptor</code> 依赖本包织入 <code>[UnitOfWork]</code> 事务切面。</li><li><a href="./caching">XiHan.Framework.Caching</a> — <code>CacheInterceptor</code> 依赖本包实现 <code>[Cacheable]</code> / <code>[CacheEvict]</code> 方法级缓存。</li></ul>`,21)])])}const g=a(s,[["render",d]]);export{k as __pageData,g as default};
